DOMAIN_SUMMARY = 'Customer Success (CS) is critical for driving product adoption, reducing churn, and increasing customer lifetime value. CS teams generate vast amounts of documentation including meeting notes, QBRs, support tickets, and feedback. Manually sifting through this evidence to identify trends, pain points, or success stories is time-consuming. This project provides a RAG solution to automate evidence review, helping CSMs quickly retrieve specific information, understand customer health, and prepare for engagements.'
USER_PERSONA = 'Customer Success Manager (CSM)'
STARTER_QUESTIONS = ["What were Acme Corp's main challenges in Q1?", 'Summarize the feedback received from Globex Corporation regarding product feature X.', "What were the key takeaways from Wayne Enterprise's onboarding process?", "Has 'Project Phoenix' been mentioned in any customer reviews?", "What were the reported successes for 'Cyberdyne Systems' last quarter?"]
WORKFLOW_STEPS = ["1. User navigates to the application's home page.", "2. User uploads customer success documents (e.g., 'customer_acme_q1_review.txt', 'customer_globex_feedback.txt') via the drag-and-drop interface.", '3. Backend receives documents, performs OCR (if PDF) and text extraction, chunks the text, generates embeddings using the local embedding model, and stores chunks and embeddings in ChromaDB.', "4. Frontend indicates 'Documents processed successfully'.", "5. User enters a natural language query into the search bar, e.g., 'What were Acme Corp's Q1 challenges?'.", "6. Frontend sends the query to the backend's RAG Query Service.", '7. Backend embeds the user query, performs a vector search in ChromaDB to retrieve the most relevant text chunks.', "8. Backend constructs a prompt using the retrieved chunks as context and the user's original query."]
BUSINESS_RULES = ['All AI-generated responses must cite the specific source document(s) and relevant text chunks they were derived from.', 'If information cannot be found within the provided documents, the system must explicitly state that it does not have the answer based on the available context.', 'Document ingestion should support .txt, .pdf, and .docx file types.', 'Maximum file size for upload is 10MB per document (configurable).', 'Retrieved chunks for RAG should be limited to the top 5 most relevant for brevity and cost/token management.', 'Only text content from documents is indexed; images or other media are ignored.', 'Embeddings for a document must be regenerated if the document content is updated/re-uploaded (simple re-ingestion workflow).']
TOOL_CATALOG = [{'name': 'document_retriever', 'description': "Retrieves relevant text chunks from the vector database based on a user's natural language query. It acts as the primary information source for the RAG system."}]
